(function($){let settings=[];$.fn.loadMore=function(options){let loaderButton=$(this);let currentId=$(this).attr("id");let instance={id:currentId,counter:1,endpoint:"",tableBodyName:"",mappingFunction:function(data){return""},callback:function(){return},loaderClass:"load-more disabled",eofCallback:function(){return},failCallback:function(e){return},refreshParams:function(){return},params:{}};let setting={};if(typeof options==="object"){loaderButton.off().click((function(){let foundSetting=settings.find((e=>e.id==instance.id));if(foundSetting){setting=foundSetting}else{setting=Object.assign(instance,options);settings.push(setting)}loaderButton.addClass(setting.loaderClass);let page=setting.counter;page++;setting.params=setting.refreshParams();let queryString=buildQueryString(setting.params,page);$.ajax({url:`${setting.endpoint}?${queryString}`,dataType:"json",statusCode:{404:function(response){setting.failCallback(response.responseText)},500:function(response){setting.failCallback(response.responseText)},200:function(response){setting.data=response;generateContentBody(loaderButton,setting);setting.callback();updateCounter(setting.id)}},complete:function(data){loaderButton.removeClass(setting.loaderClass)}})}))}if(typeof options==="string"){if(options=="reset"){reset(currentId)}}return loaderButton};function buildQueryString(obj,counter){let queryString="";try{queryString=jQuery.param(obj)}catch(exception){queryString=""}queryString+=`&page=${counter}`;return queryString}function generateContentBody(button,setting){let html="";try{html=setting.mappingFunction(setting.data)}catch(exception){html=""}if(html==""){setting.eofCallback();button.removeClass(setting.loaderClass);return}$(`#${setting.tableBodyName}`).append(html)}function reset(id){let setting=settings.find((s=>s.id==id));if(setting)setting.counter=1}function updateCounter(id){let setting=settings.find((s=>s.id==id));if(setting)setting.counter++}})(jQuery);